598:                 let result = mem::replace(value.as_mut(), Self::dummy());
599:                 *self = result;
600:             },
601:             CalcNode::Invert(_) => {
602:                 // -(1 / -10) == -(-0.1) == 0.1
603:                 wrap_self_in_negate(self)
604:             },
605:             CalcNode::Sum(ref mut children) => {
606:                 for child in children.iter_mut() {
607:                     child.negate();
608:                 }
609:             },
610:             CalcNode::Product(_) => {
611:                 // -(2 * 3 / 4) == -(1.5)
