32: nsCSSValue::nsCSSValue(float aValue, nsCSSUnit aUnit) : mUnit(aUnit) {
33:   MOZ_ASSERT(eCSSUnit_Null == aUnit, "not a float value");
34:   mValue = aValue;
35:   MOZ_ASSERT(!std::isnan(mValue));
36: }
37: 
38: nsCSSValue::nsCSSValue(const nsCSSValue& aCopy) : mUnit(aCopy.mUnit) {
39:   if (eCSSUnit_Null != mUnit) {
40:     mValue = aCopy.mValue;
41:     MOZ_ASSERT(!std::isnan(mValue));
42:   } else {
43:     MOZ_ASSERT_UNREACHABLE("unknown unit");
44:   }
45: }
46: 
47: nsCSSValue& nsCSSValue::operator=(const nsCSSValue& aCopy) {
48:   if (this != &aCopy) {
49:     this->~nsCSSValue();
50:     new (this) nsCSSValue(aCopy);
51:   }
52:   return *this;
53: }
54: 
55: nsCSSValue& nsCSSValue::operator=(nsCSSValue&& aOther) {
56:   MOZ_ASSERT(this != &aOther, "Self assigment with rvalue reference");
57: 
58:   Reset();
59:   mUnit = aOther.mUnit;
60:   mValue = aOther.mValue;
61:   aOther.mUnit = eCSSUnit_Null;
62: 
63:   return *this;
64: }
